try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const business = $node['Split In Batches'].json;
    let post;
    try {
      const text = item.json.content[0].text;
      post = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      post = match ? JSON.parse(match[0]) : {
        post_text: 'Visit us today!',
        call_to_action_type: 'LEARN_MORE',
        call_to_action_url: 'https://maroa.ai',
        topic_type: 'STANDARD',
        local_keywords: []
      };
    }
    results.push({json: {
      business_id: business.id,
      business_name: business.business_name || '',
      email: business.email || '',
      google_business_id: business.google_business_id || '',
      google_location_id: business.google_location_id || 'me',
      post_text: post.post_text || '',
      call_to_action_type: post.call_to_action_type || 'LEARN_MORE',
      call_to_action_url: post.call_to_action_url || 'https://maroa.ai',
      topic_type: post.topic_type || 'STANDARD',
      local_keywords: post.local_keywords || []
    }});
  }
  return results;
} catch(e) {
  return [{json: {error: e.message, business_id: $node['Split In Batches'].json.id}}];
}

try {
